89	/// Returns one of the `COS_*` status codes describing `co` relative to the
90	/// calling thread `state`. Mirrors `auxstatus` in `lcorolib.c` exactly,
91	/// reading the target coroutine's `status`, call-frame depth, and stack
92	/// top through `GlobalState::threads`.
93	///
94	/// The main thread (id 0) is never stored in the registry, so a value
95	/// pointing at it is always "running" when it is the current thread.
96	/// Phase E-1 cannot resume coroutines, so any registry-resident thread
97	/// is either suspended (initial state, function still on stack) or dead
98	/// (empty stack).
99	///
100	/// C: `static int auxstatus(lua_State *L, lua_State *co)`
101	fn aux_status(state: &mut LuaState, co: &GcRef<lua_types::value::LuaThread>) -> i32 {
102	    let co_id = co.id;
103	    let g = state.global();
104	    if co_id == g.current_thread_id {
105	        return COS_RUN;
106	    }
107	    let entry = match g.threads.get(&co_id) {
108	        Some(e) => e,
109	        None => return COS_DEAD,
110	    };
111	    let co_state: &lua_vm::state::LuaState = &entry.state;
112	    let raw_status = co_state.status;
113	    if raw_status == LuaStatus::Yield as u8 {
114	        return COS_YIELD;
115	    }
116	    if raw_status != LuaStatus::Ok as u8 {
117	        return COS_DEAD;
118	    }
119	    let has_frames = co_state.ci.as_usize() > 0;
120	    if has_frames {
121	        return COS_NORM;
122	    }
123	    let ci_func = co_state.call_info[0].func.0;
124	    let top = co_state.top.0;
125	    let lua_gettop = top as i64 - ci_func as i64 - 1;
126	    if lua_gettop == 0 {
127	        COS_DEAD
128	    } else {
129	        COS_YIELD
130	    }
131	}
