156	// ── Public library functions ──────────────────────────────────────────────────
157	
158	/// `coroutine.resume(co [, val1, ...])` — attempt to resume coroutine `co`.
159	///
160	/// On success pushes `true` followed by all values yielded or returned by `co`.
161	/// On failure pushes `false` followed by the error object.
162	///
163	/// C: `static int luaB_coresume(lua_State *L)`
164	pub fn co_resume(state: &mut LuaState) -> Result<usize, LuaError> {
165	    // C: lua_State *co = getco(L);
166	    let co = get_co(state)?;
167	    // C: r = auxresume(L, co, lua_gettop(L) - 1);
168	    // PORT NOTE: lua_gettop returns the argument count; -1 excludes the coroutine
169	    // itself which sits at index 1.
170	    let narg = state.get_top() - 1;
171	    let r = aux_resume(state, co, narg);
172	    if r < 0 {
173	        // C: lua_pushboolean(L, 0); lua_insert(L, -2); return 2;
174	        state.push(LuaValue::Bool(false));
175	        state.insert(-2);
176	        Ok(2)
177	    } else {
178	        // C: lua_pushboolean(L, 1); lua_insert(L, -(r + 1)); return r + 1;
179	        state.push(LuaValue::Bool(true));
180	        state.insert(-(r + 1));
181	        Ok((r + 1) as usize)
182	    }
183	}
