326	/// `coroutine.wrap(f)` — create a coroutine and return a resuming function.
327	///
328	/// The returned function, when called, resumes the coroutine as if by
329	/// `coroutine.resume`, but raises an error rather than returning `false`.
330	///
331	/// C: `static int luaB_cowrap(lua_State *L)`
332	///
333	/// Phase A–D emulation: captures `f` as upvalue 1 of `aux_wrap`. Each
334	/// call to the returned function forwards directly to `f` with the same
335	/// args. Phase E will replace this with the real `luaB_cocreate` +
336	/// `auxresume` sequence once stackful coroutines land.
337	pub fn co_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
338	    state.check_arg_type(1, LuaType::Function)?;
339	    state.push_value_at(1)?;
340	    state.push_cclosure(aux_wrap, 1)?;
341	    Ok(1)
342	}
