344	/// `coroutine.yield([...])` — suspend the running coroutine.
345	///
346	/// All arguments are passed back as results of the corresponding `resume`.
347	///
348	/// C: `static int luaB_yield(lua_State *L)`
349	/// → `return lua_yield(L, lua_gettop(L));`
350	/// → `lua_yield(L,n)` is `lua_yieldk(L, n, 0, NULL)` (lua.h:316)
351	///
352	/// Phase A–D buffering-emulation hook: if `aux_wrap` has installed a yield
353	/// buffer on the LuaState (signalling that a `coroutine.wrap` body is
354	/// running synchronously on the main thread), append the arguments into
355	/// that buffer and return 0 values without suspending. The wrapped
356	/// function continues to run; `aux_wrap` dispenses the buffered values one
357	/// per call. If no buffer is active we fall through to the faithful
358	/// `lua_yieldk` translation, which on the main thread surfaces the C-Lua
359	/// "attempt to yield from outside a coroutine" error.
360	pub fn co_yield(state: &mut LuaState) -> Result<usize, LuaError> {
361	    if state.has_yield_buffer() {
362	        let n = state.get_top();
363	        let batch: Vec<LuaValue> = (1..=n).map(|i| state.value_at(i)).collect();
364	        state.yield_buffer_push_batch(batch);
365	        return Ok(0);
366	    }
367	    let n = state.get_top();
368	    let r = lua_vm::do_::lua_yieldk(state, n, 0, None)?;
369	    Ok(r as usize)
370	}
