372	/// `coroutine.status(co)` — return a string describing `co`'s current status.
373	///
374	/// Returns one of `"running"`, `"dead"`, `"suspended"`, or `"normal"`.
375	///
376	/// C: `static int luaB_costatus(lua_State *L)`
377	pub fn co_status(state: &mut LuaState) -> Result<usize, LuaError> {
378	    // C: lua_State *co = getco(L);
379	    let co = get_co(state)?;
380	    // C: lua_pushstring(L, statname[auxstatus(L, co)]);
381	    let idx = aux_status(state, &co) as usize;
382	    let name: &[u8] = STAT_NAMES[idx];
383	    let interned = state.intern_str(name)?;
384	    state.push(LuaValue::Str(interned));
385	    Ok(1)
386	}
