388	/// `coroutine.isyieldable([co])` — test whether a coroutine (default: current)
389	/// is in a yieldable state.
390	///
391	/// C: `static int luaB_yieldable(lua_State *L)`
392	pub fn co_isyieldable(state: &mut LuaState) -> Result<usize, LuaError> {
393	    let is_yieldable = if matches!(state.type_at(1), LuaType::None) {
394	        state.is_yieldable()
395	    } else {
396	        let co = get_co(state)?;
397	        let co_id = co.id;
398	        let g = state.global();
399	        if co_id == g.main_thread_id {
400	            false
401	        } else {
402	            let entry = g
403	                .threads
404	                .get(&co_id)
405	                .expect("thread value carries an id that must resolve in GlobalState::threads");
406	            entry.state.is_yieldable()
407	        }
408	    };
409	    state.push(LuaValue::Bool(is_yieldable));
410	    Ok(1)
411	}
